-- ============================================
-- Legislacao full-site: ricardo-ferraco / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2011-2018
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/635/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2011_2018_20260505
--
-- Filtro factual: endpoint senador/635/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=635
--   com NumOrdemAutor=1. Resultado deste snapshot: 145 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_count int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ricardo-ferraco';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ricardo-ferraco: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505';

  IF projetos_total NOT IN (0, 145) THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-ferraco: esperadas 0 rows atuais ou 145 rows alvo idempotentes em projetos_lei, encontradas %', projetos_total;
  END IF;

  IF projetos_total = 145 AND target_count <> 145 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-ferraco: 145 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'ES'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2018
    AND COALESCE(hp.periodo_fim, 9999) >= 2011;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-ferraco: mandato Senado/ES 2011-2018 nao encontrado em historico_politico';
  END IF;
END $$;

