    ('PLS', '26', 2017, 'Acrescenta os §§ 3º e 4º ao art. 895 e os §§ 9º e 10 ao art. 897, ambos da Consolidação das Leis do Trabalho – CLT, aprovada pelo Decreto-Lei nº 5.452, de 1º de maio de 1943, para determinar o não cabimento de recurso ordinário e de agravo de petição em desfavor de decisão em consonância com súmula do Tribunal Superior do Trabalho (TST) e do Supremo Tribunal Federal (STF); com súmula Vinculante do STF; com decisão proferida pelo STF em sede de repercussão geral e com decisão proferida pelo TST e pelo STF em sede de recurso repetitivo.', 'Senado', '128134', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/128134', 'ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505', 'inventario_completo_senado_autoria_substantiva_2011_2018_20260505', '{"proposicao_id_api":"128134","descricao_identificacao":"PLS 26/2017","data_apresentacao":"2017-02-15","casa":"SF","codigo_parlamentar_senado":635,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PSDB","uf_autor_no_protocolo":"ES","autor_nome":"Ricardo Ferraço","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/635/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/128134.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/128134.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/128134","coverage_id":"ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505","coverage_scope":"inventario_completo_senado_autoria_substantiva_2011_2018_20260505","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"ricardo-ferraco-senado-lote-a-20260505","snapshot_consulta_em":"2026-05-06T01:32:58.062Z"}'::jsonb),
    ('PLS', '27', 2017, 'Altera o art. 658 da Consolidação das Leis do Trabalho (CLT), aprovada pelo Decreto-Lei nº 5.452, de 1º de maio de 1943, para vedar a promoção, em primeira instância, e o acesso aos Tribunais Regionais do Trabalho e ao Tribunal Superior do Trabalho (TST) do magistrado que desrespeitar súmula vinculante do Supremo Tribunal Federal (STF); decisão proferida em sede de repercussão geral pelo STF e decisão proferida em sede de recurso repetitivo pelo STF, pelo Superior Tribunal de Justiça (STJ) e pelo Tribunal Superior do Trabalho (TST).', 'Senado', '128135', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/128135', 'ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505', 'inventario_completo_senado_autoria_substantiva_2011_2018_20260505', '{"proposicao_id_api":"128135","descricao_identificacao":"PLS 27/2017","data_apresentacao":"2017-02-15","casa":"SF","codigo_parlamentar_senado":635,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PSDB","uf_autor_no_protocolo":"ES","autor_nome":"Ricardo Ferraço","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/635/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/128135.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/128135.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/128135","coverage_id":"ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505","coverage_scope":"inventario_completo_senado_autoria_substantiva_2011_2018_20260505","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"ricardo-ferraco-senado-lote-a-20260505","snapshot_consulta_em":"2026-05-06T01:32:58.062Z"}'::jsonb),
