DO $$
DECLARE
  cand_id uuid;
  uncovered_year_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ricardo-ferraco';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ricardo-ferraco: validacao de mandato Senado pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(DISTINCT seed.ano) INTO uncovered_year_count
  FROM _seed_ricardo_ferraco_senado_lote_a_projetos seed
  WHERE NOT EXISTS (
    SELECT 1
    FROM historico_politico hp
    WHERE hp.candidato_id = cand_id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND UPPER(COALESCE(hp.estado, '')) = 'ES'
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
  );

  IF uncovered_year_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao ricardo-ferraco: existem % anos de proposicoes Senado sem cobertura em mandato Senado/ES', uncovered_year_count;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'ricardo-ferraco'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_ricardo_ferraco_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO NOTHING;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'ricardo-ferraco';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'ricardo-ferraco: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('99758', '103896', '99152', '99154', '99282', '99306', '101515', '101791', '103124', '103315', '103313', '103890', '102558', '104234', '108650', '108652', '104128', '105334', '105706', '106507', '108872', '105824', '107856', '113506', '112088', '115523', '113586', '113696', '114337', '114983', '115329', '111391', '113751', '113826', '114117', '114174', '115541', '116050', '119245', '118712', '118738', '116002', '116000', '116001', '115998', '116069', '116071', '116068', '116139', '116219', '116338', '116384', '116389', '116600', '118184', '118198', '118199', '118369', '118624', '118622', '118705', '118718', '119244', '119378', '116143', '118197', '118196', '118202', '118367', '118368', '121895', '123735', '123736', '120074', '120565', '121423', '123166', '119654', '119652', '120017', '120638', '121185', '121198', '121307', '121308', '121790', '121968', '122094', '122181', '122180', '122426', '122685', '122719', '122716', '122720', '122717', '123510', '124165', '124204', '124364', '122427', '122936', '123415', '123515', '124775', '124829', '124832', '126473', '126520', '125010', '125038', '125256', '125274', '125599', '125768', '125769', '125797', '125941', '125966', '124689', '125529', '127783', '128210', '130598', '128196', '128134', '128135', '128220', '128349', '130618', '130775', '131017', '131327', '128260', '130784', '133829', '133296', '133301', '133302', '133383', '133761', '134037', '134064', '132526', '134758');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'ricardo-ferraco-senado-completo-autoria-substantiva-2011-2018-20260505'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2011_2018_20260505';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 145 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-ferraco: esperadas 145 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF total_count <> 145 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-ferraco: total projetos_lei esperado 145, encontrado %', total_count;
  END IF;

  IF scope_count <> 145 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-ferraco: esperadas 145 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply ricardo-ferraco: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply ricardo-ferraco Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
